import React, { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";
import "../styles/RecipesPage.css";

function RecipesPage() {
  let [searchParams] = useSearchParams();

  let startSearch = searchParams.get("search") || "chicken";

  let [recipes, setRecipes] = useState([]);
  let [search, setSearch] = useState(startSearch);
  let [loading, setLoading] = useState(true);

  let [selectedCategory, setSelectedCategory] = useState("");
  let [selectedArea, setSelectedArea] = useState("");

  useEffect(() => {
    fetchRecipes(startSearch);
  }, [startSearch]);

  function fetchRecipes(name) {
    setLoading(true);

    fetch("http://localhost:5000/api/przepisy/szukaj/" + encodeURIComponent(name))
      .then((response) => response.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setRecipes(data);
        } else {
          setRecipes([]);
        }
        setLoading(false);
      })
      .catch((error) => {
        console.log(error);
        setRecipes([]);
        setLoading(false);
      });
  }

  function handleSearch() {
    if (!search.trim()) {
      return;
    }

    fetchRecipes(search);
  }

  function renderStars(value) {
    let rating = value || 4;
    let stars = [];

    for (let i = 1; i <= 5; i++) {
      if (i <= rating) {
        stars.push(
          <span key={i} className="star filled">
            ★
          </span>
        );
      } else {
        stars.push(
          <span key={i} className="star">
            ☆
          </span>
        );
      }
    }

    return stars;
  }

  let categories = useMemo(() => {
    let values = recipes.map((recipe) => recipe.kategoria).filter((value) => value);
    return [...new Set(values)];
  }, [recipes]);

  let areas = useMemo(() => {
    let values = recipes.map((recipe) => recipe.obszar).filter((value) => value);
    return [...new Set(values)];
  }, [recipes]);

  let filteredRecipes = recipes.filter((recipe) => {
    let matchCategory = !selectedCategory || recipe.kategoria === selectedCategory;
    let matchArea = !selectedArea || recipe.obszar === selectedArea;

    return matchCategory && matchArea;
  });

  let activeFilters = [];
  if (search.trim()) activeFilters.push(search);
  if (selectedCategory) activeFilters.push(selectedCategory);
  if (selectedArea) activeFilters.push(selectedArea);

  return (
    <div className="app">
      <Navbar />

      <main>
        <section className="recipes-page-hero">
          <div className="container">
            <h2>Znajdź idealny przepis</h2>
            <p>
              Wyszukuj przepisy według nazwy i filtruj wyniki według kategorii
              oraz kraju pochodzenia.
            </p>
          </div>
        </section>

        <section className="recipes-page section">
          <div className="container recipes-layout">
            <aside className="filters-box">
              <div className="filters-header">
                <h3>Filtry wyszukiwania</h3>
                <button
                  type="button"
                  className="clear-filters-btn"
                  onClick={() => {
                    setSelectedCategory("");
                    setSelectedArea("");
                  }}
                >
                  Wyczyść
                </button>
              </div>

              <div className="filter-card">
                <h4>Wyszukaj przepis</h4>
                <input
                  type="text"
                  placeholder="Np. chicken, pasta, beef"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                />
              </div>

              <div className="filter-card">
                <h4>Kategoria</h4>
                <select
                  value={selectedCategory}
                  onChange={(e) => setSelectedCategory(e.target.value)}
                >
                  <option value="">Wszystkie</option>
                  {categories.map((category, index) => (
                    <option key={index} value={category}>
                      {category}
                    </option>
                  ))}
                </select>
              </div>

              <div className="filter-card">
                <h4>Kraj / kuchnia</h4>
                <select
                  value={selectedArea}
                  onChange={(e) => setSelectedArea(e.target.value)}
                >
                  <option value="">Wszystkie</option>
                  {areas.map((area, index) => (
                    <option key={index} value={area}>
                      {area}
                    </option>
                  ))}
                </select>
              </div>

              <button className="filter-btn" onClick={handleSearch}>
                Szukaj przepisów
              </button>
            </aside>

            <div className="recipes-results-wrapper">
              <div className="results-topbar">
                <div>
                  <h3>Znalezione przepisy</h3>
                  <p className="results-count">
                    {loading ? "Ładowanie..." : `${filteredRecipes.length} wyników`}
                  </p>
                </div>

                <div className="results-actions">
                  <button type="button" className="view-btn active">
                    Lista
                  </button>
                </div>
              </div>

              <div className="active-filters">
                {activeFilters.length === 0 ? (
                  <span className="active-filter-tag">Brak aktywnych filtrów</span>
                ) : (
                  activeFilters.map((filter, index) => (
                    <span className="active-filter-tag" key={index}>
                      {filter}
                    </span>
                  ))
                )}
              </div>

              <div className="recipes-results">
                {loading ? (
                  <p>Ładowanie przepisów...</p>
                ) : filteredRecipes.length === 0 ? (
                  <p>Brak przepisów pasujących do filtrów.</p>
                ) : (
                  filteredRecipes.map((recipe) => (
                    <div className="recipe-result-card" key={recipe.id}>
                      <div className="recipe-result-image">
                        <img src={recipe.obrazek} alt={recipe.tytul} />
                      </div>

                      <div className="recipe-result-content-simple">
                        <h3>{recipe.tytul}</h3>

                        <p className="recipe-result-location">
                          🌍 {recipe.obszar || "Brak informacji o kraju"}
                        </p>

                        <div className="recipe-stars-row">
                          <div className="recipe-stars">{renderStars(4)}</div>
                          <span className="recipe-stars-text">4/5</span>
                        </div>

                        <p className="recipe-result-description">
                          {recipe.instrukcje
                            ? recipe.instrukcje.substring(0, 220) + "..."
                            : "Brak opisu przepisu."}
                        </p>

                        <div className="recipe-buttons-row">
                          {recipe.youtube ? (
                            <a
                              href={recipe.youtube}
                              target="_blank"
                              rel="noreferrer"
                              className="recipe-btn"
                            >
                              Obejrzyj przepis
                            </a>
                          ) : (
                            <button className="recipe-btn recipe-btn-disabled" disabled>
                              Brak filmu
                            </button>
                          )}

                          <button className="recipe-btn secondary-recipe-btn">
                            Szczegóły przepisu
                          </button>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </section>
      </main>

      <Footer />
    </div>
  );
}

export default RecipesPage;
